 namespace League\CommonMark\Extension\TaskList; use League\CommonMark\Block\Element\ListItem; use League\CommonMark\Block\Element\Paragraph; use League\CommonMark\Inline\Parser\InlineParserInterface; use League\CommonMark\InlineParserContext; final class TaskListItemMarkerParser implements InlineParserInterface { public function getCharacters(): array { return ['[']; } public function parse(InlineParserContext $inlineContext): bool { $container = $inlineContext->getContainer(); if ($container->hasChildren() || !($container instanceof Paragraph && $container->parent() && $container->parent() instanceof ListItem)) { return false; } $cursor = $inlineContext->getCursor(); $oldState = $cursor->saveState(); $m = $cursor->match('/\[[ xX]\]/'); if ($m === null) { return false; } if ($cursor->getNextNonSpaceCharacter() === null) { $cursor->restoreState($oldState); return false; } $isChecked = $m !== '[ ]'; $container->appendChild(new TaskListItemMarker($isChecked)); return true; } } 